SET NAMES utf8mb4;
SET time_zone='+00:00';
START TRANSACTION;
ON DUPLICATE KEY UPDATE
 is_published=VALUES(is_published),is_featured=VALUES(is_featured),display_order=VALUES(display_order),featured_image=VALUES(featured_image),category_id=VALUES(category_id),sub_category_id=VALUES(sub_category_id),updated_at=VALUES(updated_at);
COMMIT;
